import { useState, useRef, useCallback } from "react";
import { useJournalEntriesQuery, useJournalDatesQuery } from "../../hooks/use-tauri-query";
import { JournalFeed } from "./JournalFeed";
import { DateJumper } from "./DateJumper";
import { GenerateDialog } from "./GenerateDialog";

export function DashboardView() {
  const [showGenerateDialog, setShowGenerateDialog] = useState(false);
  const feedRef = useRef<HTMLDivElement>(null);

  const { data: entries = [], refetch: refetchEntries } = useJournalEntriesQuery();
  const { data: dates = [] } = useJournalDatesQuery();

  const today = new Date().toISOString().slice(0, 10);

  const handleDateClick = useCallback((date: string) => {
    const el = document.getElementById(`journal-${date}`);
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, []);

  return (
    <div className="flex flex-1 flex-col overflow-hidden">
      {/* Dashboard toolbar */}
      <div className="flex items-center justify-between border-b border-border bg-bg px-5 py-3">
        <div className="flex items-center gap-3">
          <h1 className="text-sm font-semibold text-fg">Work Journal</h1>
        </div>
        <button
          onClick={() => setShowGenerateDialog(true)}
          className="rounded-md bg-accent px-3 py-1.5 text-xs font-semibold text-white hover:bg-accent/90"
        >
          ✨ Generate Today's Summary
        </button>
      </div>

      {/* Feed + Date Jumper */}
      <div className="flex flex-1 overflow-hidden">
        <div ref={feedRef} className="flex-1 overflow-y-auto px-8 py-6">
          <div className="mx-auto max-w-[720px]">
            <JournalFeed entries={entries} />
          </div>
        </div>

        <DateJumper dates={dates} onDateClick={handleDateClick} />
      </div>

      {/* Generate dialog */}
      {showGenerateDialog && (
        <GenerateDialog
          date={today}
          onClose={() => setShowGenerateDialog(false)}
          onGenerated={() => refetchEntries()}
        />
      )}
    </div>
  );
}

