 16→
 17→#[derive(Debug, Serialize, Deserialize, Clone)]
 18→pub struct RepoSection {
 19→    pub name: String,
 20→    pub lines_added: u64,
 21→    pub lines_removed: u64,
 22→    pub accomplishments: Vec<String>,
 23→    pub pull_requests: Vec<JournalPR>,
 24→}
 25→
 26→#[derive(Debug, Serialize, Deserialize, Clone)]
 27→pub struct JournalPR {
 28→    pub title: String,
 29→    pub number: u64,
 30→    pub status: String, // "open", "merged", "closed"
 31→    pub additions: u64,
 32→    pub deletions: u64,
 33→    pub url: String,
 34→}
 35→
 36→#[derive(Debug, Serialize, Deserialize, Clone)]
 37→pub struct JournalStats {
 38→    pub lines_changed: u64,
 39→    pub sessions: u64,
 40→    pub prs: u64,
 41→    pub ai_authored_pct: u64,
 42→    pub tokens: u64,
 43→}
 44→
 45→#[derive(Debug, Serialize, Clone)]
 46→pub struct JournalDateInfo {
 47→    pub date: String,
 48→    pub has_entry: bool,
 49→    pub activity_level: u32, // 0-4
 50→}
 51→
 52→/// Get the journal directory, reading from app settings or falling back to ~/.entire/journal/.
 53→pub fn journal_dir() -> PathBuf {
 54→    let settings = crate::config::read_app_settings();
 55→    let dir = if let Some(ref p) = settings.journal_path {
 56→        PathBuf::from(p)
 57→    } else {
 58→        let home = std::env::var("HOME").unwrap_or_default();
 59→        PathBuf::from(home).join(".entire/journal")
 60→    };
 61→    let _ = fs::create_dir_all(&dir);
 62→    dir
 63→}
 64→
 65→/// List journal entries from markdown files, sorted newest first.
 66→/// `limit` defaults to 100.
 67→pub fn list_entries(limit: usize) -> Result<Vec<JournalEntry>, String> {
 68→    let dir = journal_dir();
 69→    if !dir.exists() {
 70→        return Ok(Vec::new());
 71→    }
 72→
 73→    let mut files: Vec<_> = fs::read_dir(&dir)
 74→        .map_err(|e| format!("Failed to read journal dir: {}", e))?
 75→        .filter_map(|e| e.ok())
 76→        .filter(|e| {
 77→            e.path()
 78→                .extension()
 79→                .map_or(false, |ext| ext == "md")
 80→        })
 81→        .collect();
 82→
 83→    // Sort by filename descending (YYYY-MM-DD.md sorts chronologically)
 84→    files.sort_by(|a, b| b.file_name().cmp(&a.file_name()));
 85→    files.truncate(limit);
 86→
 87→    let mut entries = Vec::new();
 88→    for file in files {
 89→        let content = fs::read_to_string(file.path())
 90→            .map_err(|e| format!("Failed to read {}: {}", file.path().display(), e))?;
 91→        match parse_markdown(&content) {
 92→            Ok(entry) => entries.push(entry),
 93→            Err(e) => eprintln!("Skipping {}: {}", file.path().display(), e),
 94→        }
 95→    }
 96→
 97→    Ok(entries)
 98→}
 99→
100→/// Get a single journal entry by date (YYYY-MM-DD).
101→pub fn get_entry(date: &str) -> Result<JournalEntry, String> {
102→    let path = journal_dir().join(format!("{}.md", date));
103→    if !path.exists() {
104→        return Err(format!("No journal entry for {}", date));
105→    }
106→    let content = fs::read_to_string(&path)
107→        .map_err(|e| format!("Failed to read entry: {}", e))?;
108→    parse_markdown(&content)
109→}
110→
111→/// Get date info for the date jumper rail.
112→pub fn list_dates(limit: usize) -> Result<Vec<JournalDateInfo>, String> {
113→    let dir = journal_dir();
114→
115→    // Build a set of dates that have entries
116→    let mut entry_dates = std::collections::HashSet::new();
117→    let mut stats_map = std::collections::HashMap::new();
118→
119→    if dir.exists() {
120→        if let Ok(read_dir) = fs::read_dir(&dir) {
121→            for entry in read_dir.filter_map(|e| e.ok()) {
122→                let path = entry.path();
123→                if path.extension().map_or(false, |ext| ext == "md") {
124→                    if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
125→                        entry_dates.insert(stem.to_string());
126→                        // Quick parse frontmatter for stats
127→                        if let Ok(content) = fs::read_to_string(&path) {
128→                            if let Ok(parsed) = parse_frontmatter_only(&content) {
129→                                stats_map.insert(stem.to_string(), parsed);
130→                            }
131→                        }
132→                    }
133→                }
134→            }
135→        }
136→    }
137→
138→    // Generate last `limit` days
139→    let today = current_date();
140→    let mut dates = Vec::new();
141→    for i in 0..limit {
142→        let date = subtract_days(&today, i as i64);
143→        let has_entry = entry_dates.contains(&date);
144→        let activity_level = stats_map
145→            .get(&date)
146→            .map(|s| {
147→                // Scale lines_changed to 0-4
148→                match s.lines_changed {
149→                    0 => 0,
150→                    1..=100 => 1,
151→                    101..=500 => 2,
152→                    501..=1000 => 3,
153→                    _ => 4,
154→                }
155→            })
156→            .unwrap_or(0);
157→
158→        dates.push(JournalDateInfo {
159→            date,
160→            has_entry,
161→            activity_level,
162→        });
163→    }
164→
165→    Ok(dates)
166→}
167→
168→/// Save a journal entry as a markdown file.
169→pub fn save_entry(entry: &JournalEntry) -> Result<(), String> {
170→    let dir = journal_dir();
171→    let path = dir.join(format!("{}.md", entry.date));
172→    let content = render_markdown(entry);
173→    fs::write(&path, content)
174→        .map_err(|e| format!("Failed to write journal entry: {}", e))
175→}
176→
177→/// Parse a journal markdown file into a JournalEntry.
178→pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
179→    // Split frontmatter from body
180→    let (frontmatter, body) = split_frontmatter(content)?;
181→
182→    // Parse YAML frontmatter
183→    let date = extract_yaml_field(&frontmatter, "date")
184→        .ok_or("Missing date in frontmatter")?;
185→    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
186→        .unwrap_or_default();
187→    let stats = parse_frontmatter_only(content)?;
188→
189→    // Parse body into repo sections and other work
190→    let (repos, other_work) = parse_body(&body);
191→
192→    Ok(JournalEntry {
193→        date,
194→        generated_at,
195→        repos,
196→        other_work,
197→        stats,
198→    })
199→}
200→
201→fn split_frontmatter(content: &str) -> Result<(String, String), String> {
202→    let content = content.trim();
203→    if !content.starts_with("---") {
204→        return Err("No frontmatter found".to_string());
205→    }
206→    let rest = &content[3..];
207→    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
208→    let frontmatter = rest[..end].trim().to_string();
209→    let body = rest[end + 3..].trim().to_string();
210→    Ok((frontmatter, body))
211→}
212→
213→fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
214→    for line in yaml.lines() {
215→        let line = line.trim();
216→        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
217→            let value = rest.trim().trim_matches('"').trim_matches('\'');
218→            if !value.is_empty() {
219→                return Some(value.to_string());
220→            }
221→        }
222→    }
223→    None
224→}
225→
226→fn parse_frontmatter_only(content: &str) -> Result<JournalStats, String> {
227→    let (frontmatter, _) = split_frontmatter(content)?;
228→
229→    let lines_changed = extract_yaml_field(&frontmatter, "lines_changed")
230→        .and_then(|v| v.parse().ok())
231→        .unwrap_or(0);
232→    let sessions = extract_yaml_field(&frontmatter, "sessions")
233→        .and_then(|v| v.parse().ok())
234→        .unwrap_or(0);
235→    let prs = extract_yaml_field(&frontmatter, "prs")
236→        .and_then(|v| v.parse().ok())
237→        .unwrap_or(0);
238→    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
239→        .and_then(|v| v.parse().ok())
240→        .unwrap_or(0);
241→    let tokens = extract_yaml_field(&frontmatter, "tokens")
242→        .and_then(|v| v.parse().ok())
243→        .unwrap_or(0);
244→
245→    Ok(JournalStats {
246→        lines_changed,
247→        sessions,
248→        prs,
249→        ai_authored_pct,
250→        tokens,
251→    })
252→}
253→
254→fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
255→    let mut repos = Vec::new();
256→    let mut other_work = Vec::new();
257→    let mut current_repo: Option<RepoSection> = None;
258→    let mut in_prs = false;
259→    let mut in_other_work = false;
260→
261→    for line in body.lines() {
262→        let trimmed = line.trim();
263→
264→        // H2 heading = repo name or "Other Work"
265→        if let Some(heading) = trimmed.strip_prefix("## ") {
266→            // Save previous repo
267→            if let Some(repo) = current_repo.take() {
268→                repos.push(repo);
269→            }
270→            in_prs = false;
271→
272→            if heading == "Other Work" {
273→                in_other_work = true;
274→                continue;
275→            }
276→
277→            in_other_work = false;
278→            current_repo = Some(RepoSection {
279→                name: heading.to_string(),
280→                lines_added: 0,
281→                lines_removed: 0,
282→                accomplishments: Vec::new(),
283→                pull_requests: Vec::new(),
284→            });
285→            continue;
286→        }
287→
288→        // H3 heading = "Pull Requests" subsection
289→        if trimmed.starts_with("### Pull Requests") {
290→            in_prs = true;
291→            continue;
292→        }
293→
294→        // Lines diff stats: _+716 -131_
295→        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
296→            if let Some(ref mut repo) = current_repo {
297→                let inner = &trimmed[1..trimmed.len() - 1];
298→                let parts: Vec<&str> = inner.split_whitespace().collect();
299→                if parts.len() == 2 {
300→                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
301→                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
302→                }
303→            }
304→            continue;
305→        }
306→
307→        // Bullet points
308→        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
309→            if in_other_work {
310→                other_work.push(bullet_content.to_string());
311→            } else if in_prs {
312→                if let Some(ref mut repo) = current_repo {
313→                    if let Some(pr) = parse_pr_line(bullet_content) {
314→                        repo.pull_requests.push(pr);
315→                    }
316→                }
317→            } else if let Some(ref mut repo) = current_repo {
318→                repo.accomplishments.push(bullet_content.to_string());
319→            }
320→        }
321→    }
322→
323→    // Don't forget last repo
324→    if let Some(repo) = current_repo {
325→        repos.push(repo);
326→    }
327→
328→    (repos, other_work)
329→}
330→
331→/// Parse a PR line like: [**title**](url) #142 — merged  OR  **title** #142 — merged
332→fn parse_pr_line(line: &str) -> Option<JournalPR> {
333→    let (title, url, rest) = if line.starts_with("[**") {
334→        // [**title**](url) #number — status
335→        let bold_end = line.find("**](")?;
336→        let title = line[3..bold_end].to_string();
337→        let url_start = bold_end + 4;
338→        let url_end = line[url_start..].find(')')? + url_start;
339→        let url = line[url_start..url_end].to_string();
340→        let rest = &line[url_end + 1..];
341→        (title, url, rest)
342→    } else {
343→        // **title** #number — status (legacy)
344→        let bold_start = line.find("**")?;
345→        let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
346→        let title = line[bold_start + 2..bold_end].to_string();
347→        let rest = &line[bold_end + 2..];
348→        (title, String::new(), rest)
349→    };
350→
351→    let hash_pos = rest.find('#')?;
352→    let after_hash = &rest[hash_pos + 1..];
353→
354→    // Find the number (digits until non-digit)
355→    let num_end = after_hash.find(|c: char| !c.is_ascii_digit()).unwrap_or(after_hash.len());
356→    let number: u64 = after_hash[..num_end].parse().ok()?;
357→
358→    // Find status after — or -
359→    let status = if let Some(dash_pos) = rest.find('—').or_else(|| rest.find(" - ")) {
360→        let s = rest[dash_pos..].trim_start_matches('—').trim_start_matches(" - ").trim();
361→        s.to_string()
362→    } else {
363→        "open".to_string()
364→    };
365→
366→    Some(JournalPR {
367→        title,
368→        number,
369→        status,
370→        additions: 0,
371→        deletions: 0,
372→        url,
373→    })
374→}
375→
376→/// Render a JournalEntry as a markdown string.
377→pub fn render_markdown(entry: &JournalEntry) -> String {
378→    let mut out = String::new();
379→
380→    // Frontmatter
381→    out.push_str("---\n");
382→    out.push_str(&format!("date: {}\n", entry.date));
383→    out.push_str(&format!("generated_at: {}\n", entry.generated_at));
384→
385→    // Repos list
386→    out.push_str("repos:\n");
387→    for repo in &entry.repos {
388→        out.push_str(&format!("  - {}\n", repo.name));
389→    }
390→
391→    // Stats
392→    out.push_str("stats:\n");
393→    out.push_str(&format!("  lines_changed: {}\n", entry.stats.lines_changed));
394→    out.push_str(&format!("  sessions: {}\n", entry.stats.sessions));
395→    out.push_str(&format!("  prs: {}\n", entry.stats.prs));
396→    out.push_str(&format!("  ai_authored_pct: {}\n", entry.stats.ai_authored_pct));
397→    out.push_str(&format!("  tokens: {}\n", entry.stats.tokens));
398→    out.push_str("---\n\n");
399→
400→    // Repo sections
401→    for repo in &entry.repos {
402→        out.push_str(&format!("## {}\n", repo.name));
403→        out.push_str(&format!("_+{} -{}_ \n\n", repo.lines_added, repo.lines_removed));
404→
405→        for item in &repo.accomplishments {
406→            out.push_str(&format!("- {}\n", item));
407→        }
408→
409→        if !repo.pull_requests.is_empty() {
410→            out.push_str("\n### Pull Requests\n");
411→            for pr in &repo.pull_requests {
412→                if pr.url.is_empty() {
413→                    out.push_str(&format!("- **{}** #{} — {}\n", pr.title, pr.number, pr.status));
414→                } else {
415→                    out.push_str(&format!("- [**{}**]({}) #{} — {}\n", pr.title, pr.url, pr.number, pr.status));
416→                }
417→            }
418→        }
419→
420→        out.push('\n');
421→    }
422→
423→    // Other work
424→    if !entry.other_work.is_empty() {
425→        out.push_str("## Other Work\n");
426→        for item in &entry.other_work {
427→            out.push_str(&format!("- {}\n", item));
428→        }
429→    }
430→
431→    out
432→}
