434→pub(crate) fn current_date() -> String {
435→    let now = std::time::SystemTime::now()
436→        .duration_since(std::time::UNIX_EPOCH)
437→        .unwrap_or_default()
438→        .as_secs();
439→    format_unix_date(now as i64)
440→}
441→
442→pub fn format_unix_date(secs: i64) -> String {
443→    // Simple date formatting from unix timestamp
444→    let days = secs / 86400;
445→    let (year, month, day) = days_to_ymd(days);
446→    format!("{:04}-{:02}-{:02}", year, month, day)
447→}
448→
449→pub(crate) fn subtract_days(date: &str, n: i64) -> String {
450→    // Parse YYYY-MM-DD, subtract n days, return YYYY-MM-DD
451→    let parts: Vec<i64> = date.split('-').filter_map(|p| p.parse().ok()).collect();
452→    if parts.len() != 3 {
453→        return date.to_string();
454→    }
455→    let total_days = ymd_to_days(parts[0], parts[1], parts[2]) - n;
456→    let (y, m, d) = days_to_ymd(total_days);
457→    format!("{:04}-{:02}-{:02}", y, m, d)
458→}
459→
460→fn ymd_to_days(year: i64, month: i64, day: i64) -> i64 {
461→    let mut days: i64 = 0;
462→    for y in 1970..year {
463→        days += if is_leap(y) { 366 } else { 365 };
464→    }
465→    let month_lengths = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
466→    for m in 1..month {
467→        days += month_lengths[m as usize];
468→        if m == 2 && is_leap(year) {
469→            days += 1;
470→        }
471→    }
472→    days + day - 1
473→}
474→
475→fn days_to_ymd(mut days: i64) -> (i64, i64, i64) {
476→    let mut year = 1970;
477→    loop {
478→        let year_days = if is_leap(year) { 366 } else { 365 };
479→        if days < year_days {
480→            break;
481→        }
482→        days -= year_days;
483→        year += 1;
484→    }
485→    let month_lengths = if is_leap(year) {
486→        [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
487→    } else {
488→        [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
489→    };
490→    let mut month = 1;
491→    for &ml in &month_lengths {
492→        if days < ml {
493→            break;
494→        }
495→        days -= ml;
496→        month += 1;
497→    }
498→    (year, month, days + 1)
499→}
500→
501→fn is_leap(y: i64) -> bool {
502→    y % 4 == 0 && (y % 100 != 0 || y % 400 == 0)
503→}
