  6→/// Parse a GitHub owner/repo from a git remote URL.
  7→/// Handles: https://github.com/owner/repo.git, git@github.com:owner/repo.git
  8→pub fn parse_github_remote(remote_url: &str) -> Option<(String, String)> {
  9→    let url = remote_url.trim().trim_end_matches(".git");
 10→
 11→    // SSH: git@github.com:owner/repo
 12→    if let Some(rest) = url.strip_prefix("git@github.com:") {
 13→        let parts: Vec<&str> = rest.splitn(2, '/').collect();
 14→        if parts.len() == 2 {
 15→            return Some((parts[0].to_string(), parts[1].to_string()));
 16→        }
 17→    }
 18→
 19→    // HTTPS: https://github.com/owner/repo
 20→    if url.contains("github.com/") {
 21→        let after = url.split("github.com/").nth(1)?;
 22→        let parts: Vec<&str> = after.splitn(2, '/').collect();
 23→        if parts.len() == 2 {
 24→            return Some((parts[0].to_string(), parts[1].to_string()));
 25→        }
 26→    }
 27→
 28→    None
 29→}
 30→
 31→/// Get the origin remote URL for a repo using git CLI.
 32→pub fn get_remote_url(repo_path: &str) -> Option<String> {
 33→    let output = Command::new("git")
 34→        .args(["remote", "get-url", "origin"])
 35→        .current_dir(repo_path)
 36→        .output()
 37→        .ok()?;
 38→
 39→    if output.status.success() {
 40→        Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
 41→    } else {
 42→        None
 43→    }
 44→}
 45→
 46→/// Get a GitHub token from env var or gh CLI.
 47→fn get_github_token() -> Option<String> {
 48→    if let Ok(token) = std::env::var("GITHUB_TOKEN") {
 49→        if !token.is_empty() {
 50→            return Some(token);
 51→        }
 52→    }
 53→
 54→    // Fall back to gh CLI
 55→    let output = Command::new("gh")
 56→        .args(["auth", "token"])
 57→        .output()
 58→        .ok()?;
 59→
 60→    if output.status.success() {
 61→        let token = String::from_utf8_lossy(&output.stdout).trim().to_string();
 62→        if !token.is_empty() {
 63→            return Some(token);
 64→        }
 65→    }
 66→
 67→    None
 68→}
