 89→/// Get the authenticated GitHub user's login name.
 90→fn get_github_username(token: &str) -> Option<String> {
 91→    let client = reqwest::blocking::Client::builder()
 92→        .timeout(std::time::Duration::from_secs(10))
 93→        .build()
 94→        .ok()?;
 95→    let resp = client
 96→        .get("https://api.github.com/user")
 97→        .header("Authorization", format!("Bearer {}", token))
 98→        .header("User-Agent", "entire-desktop")
 99→        .send()
100→        .ok()?;
101→    if !resp.status().is_success() {
102→        return None;
103→    }
104→    let body: serde_json::Value = resp.json().ok()?;
105→    body["login"].as_str().map(|s| s.to_string())
106→}
