108→/// Fetch PRs for a repo that were updated on a given date.
109→/// Returns empty vec if no GitHub token is available (graceful degradation).
110→pub fn fetch_prs_for_date(
111→    repo_path: &str,
112→    date: &str,
113→) -> Vec<JournalPR> {
114→    let remote_url = match get_remote_url(repo_path) {
115→        Some(url) => url,
116→        None => return Vec::new(),
117→    };
118→
119→    let (owner, repo) = match parse_github_remote(&remote_url) {
120→        Some(pair) => pair,
121→        None => return Vec::new(),
122→    };
123→
124→    let token = match get_github_token() {
125→        Some(t) => t,
126→        None => return Vec::new(),
127→    };
128→
129→    let username = get_github_username(&token).unwrap_or_default();
130→    let author_filter = if username.is_empty() {
131→        String::new()
132→    } else {
133→        format!(" author:{}", username)
134→    };
135→    let query = format!("repo:{}/{} is:pr{} updated:{}", owner, repo, author_filter, date);
136→    let url = format!(
137→        "https://api.github.com/search/issues?q={}&per_page=100",
138→        urlencoded(&query)
139→    );
140→
141→    let client = match reqwest::blocking::Client::builder()
142→        .timeout(std::time::Duration::from_secs(15))
143→        .build()
144→    {
145→        Ok(c) => c,
146→        Err(_) => return Vec::new(),
147→    };
148→
149→    let response = client
150→        .get(&url)
151→        .header("Authorization", format!("Bearer {}", token))
152→        .header("Accept", "application/vnd.github+json")
153→        .header("User-Agent", "entire-desktop")
154→        .header("X-GitHub-Api-Version", "2022-11-28")
155→        .send();
156→
157→    let response = match response {
158→        Ok(r) => r,
159→        Err(e) => {
160→            eprintln!("GitHub API error: {}", e);
161→            return Vec::new();
162→        }
163→    };
164→
165→    if !response.status().is_success() {
166→        eprintln!("GitHub API returned status: {}", response.status());
167→        return Vec::new();
168→    }
169→
170→    let search: SearchResponse = match response.json() {
171→        Ok(s) => s,
172→        Err(e) => {
173→            eprintln!("Failed to parse GitHub response: {}", e);
174→            return Vec::new();
175→        }
176→    };
177→
178→    search
179→        .items
180→        .into_iter()
181→        .map(|item| {
182→            let status = if item.pull_request
183→                .as_ref()
184→                .and_then(|pr| pr.merged_at.as_ref())
185→                .is_some()
186→            {
187→                "merged".to_string()
188→            } else if item.state == "closed" {
189→                "closed".to_string()
190→            } else {
191→                "open".to_string()
192→            };
193→
194→            JournalPR {
195→                title: item.title,
196→                number: item.number,
197→                status,
198→                additions: 0,
199→                deletions: 0,
200→                url: item.html_url,
201→            }
202→        })
203→        .collect()
204→}
205→
206→fn urlencoded(s: &str) -> String {
207→    s.replace(' ', "+")
208→        .replace(':', "%3A")
209→        .replace('/', "%2F")
210→}
