 93→/// Build a Claude prompt that aggregates data from multiple repos.
 94→fn build_multi_repo_prompt(
 95→    date: &str,
 96→    repo_data: &[(String, DayData, Vec<journal::JournalPR>)],
 97→    extra_items: &[String],
 98→) -> String {
 99→    let mut prompt = format!(
100→        "Generate a daily work journal entry for {} across all repositories.\n\n",
101→        date
102→    );
103→
104→    for (repo_name, day_data, prs) in repo_data {
105→        prompt.push_str(&format!("# Repository: {}\n\n", repo_name));
106→
107→        prompt.push_str("## Session Activity\n");
108→        if day_data.summaries.is_empty() {
109→            prompt.push_str("No code sessions recorded for this day.\n");
110→        } else {
111→            for s in &day_data.summaries {
112→                prompt.push_str(&format!("{}\n", s));
113→            }
114→        }
115→
116→        if !day_data.files_touched.is_empty() {
117→            prompt.push_str("\n## Files Touched\n");
118→            for f in &day_data.files_touched {
119→                prompt.push_str(&format!("- {}\n", f));
120→            }
121→        }
122→
123→        if !prs.is_empty() {
124→            prompt.push_str("\n## Pull Requests\n");
125→            for pr in prs {
126→                prompt.push_str(&format!(
127→                    "- #{} \"{}\" ({})\n",
128→                    pr.number, pr.title, pr.status
129→                ));
130→            }
131→        }
132→
133→        prompt.push('\n');
134→    }
135→
136→    if !extra_items.is_empty() {
137→        prompt.push_str("# Non-Code Work (provided by user)\n");
138→        for item in extra_items {
139→            prompt.push_str(&format!("- {}\n", item));
140→        }
141→    }
142→
143→    prompt.push_str("\n## Instructions\n");
