195→/// Generate a journal entry for a given date, aggregating across all registered repos.
196→pub fn generate_entry(
197→    date: &str,
198→    extra_items: Option<Vec<String>>,
199→) -> Result<journal::JournalEntry, String> {
200→    let extra = extra_items.unwrap_or_default();
201→    let repo_paths = config::discover_repos();
202→
203→    if repo_paths.is_empty() {
204→        return Err("No registered repos found. Register a repo first.".to_string());
205→    }
206→
207→    // Gather data from all repos
208→    let mut all_repo_data: Vec<(String, DayData, Vec<journal::JournalPR>)> = Vec::new();
209→    for repo_path in &repo_paths {
210→        let repo_name = std::path::Path::new(repo_path)
211→            .file_name()
212→            .map(|n| n.to_string_lossy().to_string())
213→            .unwrap_or_else(|| "unknown".to_string());
214→
215→        let day_data = gather_day_data(repo_path, date).unwrap_or(DayData {
216→            summaries: Vec::new(),
217→            files_touched: Vec::new(),
218→            total_sessions: 0,
219→            total_tokens: 0,
220→            avg_ai_pct: 0,
221→            lines_changed: 0,
222→        });
223→
224→        let prs = github::fetch_prs_for_date(repo_path, date);
225→        all_repo_data.push((repo_name, day_data, prs));
226→    }
227→
228→    // Build prompt across all repos
229→    let prompt = build_multi_repo_prompt(date, &all_repo_data, &extra);
230→
231→    let api_key = config::read_app_settings()
232→        .anthropic_api_key
233→        .filter(|k| !k.is_empty())
234→        .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
235→        .ok_or_else(|| {
236→            "Anthropic API key is not configured. Set it in Settings or as ANTHROPIC_API_KEY env var."
237→                .to_string()
238→        })?;
239→
240→    let model = std::env::var("ANTHROPIC_MODEL")
241→        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
242→
243→    let client = reqwest::blocking::Client::builder()
244→        .timeout(std::time::Duration::from_secs(90))
245→        .build()
246→        .map_err(|e| format!("Failed to build HTTP client: {}", e))?;
247→
248→    let response = client
249→        .post("https://api.anthropic.com/v1/messages")
250→        .header("x-api-key", &api_key)
251→        .header("anthropic-version", "2023-06-01")
252→        .header("content-type", "application/json")
253→        .json(&AnthropicRequest {
254→            model,
255→            max_tokens: 2_000,
256→            temperature: 0.3,
257→            system: "You are a work journal assistant. Generate concise daily summaries of development work. Respond with JSON only.".to_string(),
258→            messages: vec![AnthropicMessage {
259→                role: "user".to_string(),
260→                content: prompt,
261→            }],
262→        })
263→        .send()
264→        .map_err(|e| format!("Anthropic request failed: {}", e))?
265→        .error_for_status()
266→        .map_err(|e| format!("Anthropic request failed: {}", e))?;
267→
268→    let body: AnthropicResponse = response
269→        .json()
270→        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
271→
272→    let text = body
273→        .content
274→        .into_iter()
275→        .filter(|block| block.kind == "text")
276→        .filter_map(|block| block.text)
277→        .collect::<Vec<_>>()
278→        .join("\n");
279→
280→    // Strip markdown code fences if present
281→    let json_text = text
282→        .trim()
283→        .trim_start_matches("```json")
284→        .trim_start_matches("```")
285→        .trim_end_matches("```")
286→        .trim();
287→
288→    let ai_response: AiResponse = serde_json::from_str(json_text)
289→        .map_err(|e| format!("Failed to parse AI response: {} — raw: {}", e, json_text))?;
290→
291→    // Build the full entry
292→    let generated_at = {
293→        let now = std::time::SystemTime::now()
294→            .duration_since(std::time::UNIX_EPOCH)
295→            .unwrap_or_default()
296→            .as_secs();
297→        format!("{}T00:00:00Z", journal::format_unix_date(now as i64))
298→    };
299→
300→    // Build a lookup from repo name to (day_data, prs)
301→    let repo_lookup: std::collections::HashMap<String, &(String, DayData, Vec<journal::JournalPR>)> =
302→        all_repo_data.iter().map(|r| (r.0.clone(), r)).collect();
303→
304→    // Map AI repo sections with their matching data
305→    let repos: Vec<journal::RepoSection> = ai_response
306→        .repos
307→        .into_iter()
308→        .map(|ai_repo| {
309→            let (lines_added, lines_removed, repo_prs) =
310→                if let Some((_, day_data, prs)) = repo_lookup.get(&ai_repo.name) {
311→                    (day_data.lines_changed / 2, day_data.lines_changed / 4, prs.clone())
312→                } else {
313→                    (0, 0, Vec::new())
314→                };
315→
316→            journal::RepoSection {
317→                name: ai_repo.name,
318→                lines_added,
319→                lines_removed,
320→                accomplishments: ai_repo.accomplishments,
321→                pull_requests: repo_prs,
322→            }
323→        })
324→        .collect();
325→
326→    // Aggregate stats across all repos
327→    let total_lines_changed: u64 = all_repo_data.iter().map(|(_, d, _)| d.lines_changed).sum();
328→    let total_sessions: u64 = all_repo_data.iter().map(|(_, d, _)| d.total_sessions).sum();
329→    let total_tokens: u64 = all_repo_data.iter().map(|(_, d, _)| d.total_tokens).sum();
330→    let total_prs: u64 = repos.iter().map(|r| r.pull_requests.len() as u64).sum();
331→    let avg_ai_pct = {
332→        let pcts: Vec<u64> = all_repo_data.iter().map(|(_, d, _)| d.avg_ai_pct).filter(|p| *p > 0).collect();
333→        if pcts.is_empty() { 0 } else { pcts.iter().sum::<u64>() / pcts.len() as u64 }
334→    };
335→
336→    let entry = journal::JournalEntry {
337→        date: date.to_string(),
338→        generated_at,
339→        repos,
340→        other_work: ai_response.other_work,
341→        stats: journal::JournalStats {
342→            lines_changed: total_lines_changed,
343→            sessions: total_sessions,
344→            prs: total_prs,
345→            ai_authored_pct: avg_ai_pct,
346→            tokens: total_tokens,
347→        },
348→    };
349→
350→    // Save to global journal dir
351→    journal::save_entry(&entry)?;
352→
353→    Ok(entry)
354→}
