561→fn call_anthropic_semantic_review(prompt: &str) -> Result<String, String> {
562→    let api_key = config::read_app_settings()
563→        .anthropic_api_key
564→        .filter(|k| !k.is_empty())
565→        .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
566→        .ok_or_else(|| "Anthropic API key is not configured. Set it in Settings or as ANTHROPIC_API_KEY env var.".to_string())?;
567→    let model = std::env::var("ANTHROPIC_MODEL")
568→        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
569→
570→    let client = reqwest::blocking::Client::builder()
571→        .timeout(std::time::Duration::from_secs(90))
572→        .build()
573→        .map_err(|e| format!("Failed to build Anthropic client: {}", e))?;
574→
575→    let response = client
576→        .post("https://api.anthropic.com/v1/messages")
577→        .header("x-api-key", api_key)
578→        .header("anthropic-version", "2023-06-01")
579→        .header("content-type", "application/json")
580→        .json(&AnthropicRequest {
581→            model,
582→            max_tokens: 2_000,
583→            temperature: 0.2,
584→            system: "You are reviewing a git diff. Return JSON only with precise, line-linked explanations of the most important changes.".to_string(),
585→            messages: vec![AnthropicMessage {
586→                role: "user".to_string(),
587→                content: prompt.to_string(),
588→            }],
589→        })
590→        .send()
591→        .map_err(|e| format!("Anthropic request failed: {}", e))?
592→        .error_for_status()
593→        .map_err(|e| format!("Anthropic request failed: {}", e))?;
594→
595→    let body: AnthropicResponse = response
596→        .json()
597→        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
598→
599→    let text = body
600→        .content
601→        .into_iter()
602→        .filter(|block| block.kind == "text")
603→        .filter_map(|block| block.text)
604→        .collect::<Vec<_>>()
605→        .join("\n");
606→
607→    if text.trim().is_empty() {
608→        return Err("Anthropic response did not include any text output".to_string());
609→    }
610→
611→    Ok(text)
612→}
