634→#[tauri::command]
635→fn run_checkpoint_semantic_review(
636→    repo_path: String,
637→    checkpoint_id: String,
638→    commit_sha: String,
639→) -> Result<semantic_review::RunCheckpointSemanticReviewResponse, String> {
640→    if checkpoint_id.len() < 2 {
641→        return Err("Invalid checkpoint ID".to_string());
642→    }
643→    if commit_sha.is_empty() {
644→        return Err("No commit SHA available for this checkpoint".to_string());
645→    }
646→
647→    let repo = git::open_repo(&repo_path)?;
648→    let files = collect_checkpoint_diff(&repo, &commit_sha)?;
649→    if files.is_empty() {
650→        return Ok(semantic_review::RunCheckpointSemanticReviewResponse {
651→            review_run_id: generate_review_run_id(),
652→            annotations: Vec::new(),
653→        });
654→    }
655→
656→    let transcripts = load_sanitized_checkpoint_transcripts(&repo, &checkpoint_id)?;
657→    let prompt = semantic_review::build_prompt(&files, &transcripts);
658→    let raw_text = call_anthropic_semantic_review(&prompt)?;
659→    let parsed = semantic_review::parse_response_text(&raw_text)?;
660→    let annotations = semantic_review::resolve_annotations(&files, parsed);
661→
662→    Ok(semantic_review::RunCheckpointSemanticReviewResponse {
663→        review_run_id: generate_review_run_id(),
664→        annotations,
665→    })
666→}
