787→#[cfg_attr(mobile, tauri::mobile_entry_point)]
788→pub fn run() {
789→    tauri::Builder::default()
790→        .plugin(tauri_plugin_opener::init())
791→        .plugin(tauri_plugin_dialog::init())
792→        .plugin(tauri_plugin_window_state::Builder::default().build())
793→        .manage(Mutex::new(AppState {
794→            watched_repos: HashSet::new(),
795→        }))
796→        .manage(Mutex::new(ghostty::GhosttyState::new()))
797→        .setup(|app| {
798→            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
799→            // ghostty_app_tick processes Cocoa/Metal events and must run on the
800→            // main thread.
801→            {
802→                use block2::RcBlock;
803→                use objc2_foundation::NSTimer;
804→
805→                let handle = app.handle().clone();
806→                let tick_block = RcBlock::new(move |_timer| {
807→                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
808→                    let mutex = state.inner();
809→                    if let Ok(gs) = mutex.lock() {
810→                        if let Some(app) = gs.app.as_ref() {
811→                            app.tick();
812→                        }
813→                    }
814→                });
815→
816→                let _tick_timer = unsafe {
817→                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
818→                        1.0 / 60.0,
819→                        true,
820→                        &tick_block,
821→                    )
822→                };
823→            }
