 89→/// List all checkpoints from the entire/checkpoints/v1 branch
 90→pub fn list_checkpoints(
 91→    repo: &Repository,
 92→    filter_branch: &str,
 93→) -> Result<Vec<CheckpointSummary>, String> {
 94→    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
 95→        Ok(b) => b,
 96→        Err(_) => return Ok(Vec::new()), // No checkpoints branch yet
 97→    };
 98→
 99→    let commit = branch_ref
100→        .get()
101→        .peel_to_commit()
102→        .map_err(|e| format!("Failed to get checkpoint commit: {}", e))?;
103→
104→    let tree = commit
105→        .tree()
106→        .map_err(|e| format!("Failed to get tree: {}", e))?;
107→
108→    let mut checkpoints = Vec::new();
109→
110→    // Walk the sharded directory structure: <id[:2]>/<id[2:]>/metadata.json
111→    tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
112→        let name = match entry.name() {
113→            Some(n) => n,
114→            None => return git2::TreeWalkResult::Ok,
115→        };
116→
117→        // Look for metadata.json at the checkpoint level (e.g., "a1/b2c3d4/metadata.json")
118→        if name == "metadata.json" && !dir.is_empty() {
119→            // dir looks like "a1/b2c3d4/" — that's 2 levels deep
120→            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
121→            if parts.len() == 2 {
122→                // This is a root checkpoint metadata.json
123→                if let Ok(blob) = repo.find_blob(entry.id()) {
124→                    if let Ok(content) = std::str::from_utf8(blob.content()) {
125→                        if let Ok(meta) = serde_json::from_str::<RawCheckpointMetadata>(content) {
126→                            let branch = meta.branch.clone().unwrap_or_default();
127→                            if filter_branch.is_empty() || branch == filter_branch {
128→                                let cp = build_checkpoint_summary(
129→                                    repo,
130→                                    &tree,
131→                                    dir,
132→                                    &meta,
133→                                );
134→                                if let Ok(cp) = cp {
135→                                    checkpoints.push(cp);
136→                                }
137→                            }
138→                        }
139→                    }
140→                }
141→            }
142→        }
143→
144→        git2::TreeWalkResult::Ok
145→    })
146→    .map_err(|e| format!("Tree walk error: {}", e))?;
147→
148→    // Sort by created_at descending
149→    checkpoints.sort_by(|a, b| b.created_at.cmp(&a.created_at));
