  8→/// Gather checkpoint data for a specific date from a repo.
  9→fn gather_day_data(repo_path: &str, date: &str) -> Result<DayData, String> {
 10→    let repo = git::open_repo(repo_path)?;
 11→
 12→    // List all checkpoints (no branch filter — we want cross-branch)
 13→    let all_checkpoints = checkpoint::list_checkpoints(&repo, "")?;
 14→
 15→    // Filter to checkpoints created on the target date
 16→    let day_checkpoints: Vec<_> = all_checkpoints
 17→        .into_iter()
 18→        .filter(|cp| cp.created_at.starts_with(date))
 19→        .collect();
 20→
 21→    let mut total_sessions: u64 = 0;
 22→    let mut total_tokens: u64 = 0;
 23→    let mut total_agent_pct_sum: f64 = 0.0;
 24→    let mut total_agent_pct_count: u64 = 0;
 25→
 26→    let mut summaries = Vec::new();
 27→
 28→    for cp in &day_checkpoints {
 29→        total_sessions += cp.sessions.len() as u64;
 30→        if let Some(ref tu) = cp.token_usage {
 31→            total_tokens += tu.input_tokens + tu.output_tokens;
 32→        }
 33→
 34→        for session in &cp.sessions {
 35→            if let Some(ref attr) = session.initial_attribution {
 36→                total_agent_pct_sum += attr.agent_percentage;
 37→                total_agent_pct_count += 1;
 38→            }
 39→
 40→            let intent = session
 41→                .summary
 42→                .as_ref()
 43→                .map(|s| s.intent.clone())
 44→                .unwrap_or_default();
 45→            let outcome = session
 46→                .summary
 47→                .as_ref()
 48→                .map(|s| s.outcome.clone())
 49→                .unwrap_or_default();
 50→
 51→            summaries.push(format!(
 52→                "- [{}] {}: {} → {}",
 53→                cp.branch, cp.commit_message, intent, outcome
 54→            ));
 55→        }
 56→    }
 57→
 58→    let avg_ai_pct = if total_agent_pct_count > 0 {
 59→        (total_agent_pct_sum / total_agent_pct_count as f64).round() as u64
 60→    } else {
 61→        0
 62→    };
 63→
 64→    // Gather files touched
 65→    let files_touched: Vec<String> = day_checkpoints
 66→        .iter()
 67→        .flat_map(|cp| cp.files_touched.iter().cloned())
 68→        .collect::<std::collections::HashSet<_>>()
 69→        .into_iter()
 70→        .collect();
 71→
 72→    let lines_changed = files_touched.len() as u64 * 30; // rough estimate
 73→
 74→    Ok(DayData {
 75→        summaries,
 76→        files_touched,
 77→        total_sessions,
 78→        total_tokens,
 79→        avg_ai_pct,
 80→        lines_changed,
 81→    })
 82→}
