 84→struct DayData {
 85→    summaries: Vec<String>,
 86→    files_touched: Vec<String>,
 87→    total_sessions: u64,
 88→    total_tokens: u64,
 89→    avg_ai_pct: u64,
 90→    lines_changed: u64,
