 35→pub fn open_repo(path: &str) -> Result<Repository, String> {
 36→    Repository::open(path).map_err(|e| format!("Failed to open repo: {}", e))
 37→}
 38→
 39→pub fn list_branches(repo: &Repository) -> Result<Vec<BranchInfo>, String> {
 40→    let mut branches = Vec::new();
 41→    let head = repo.head().ok();
 42→    let head_name = head
 43→        .as_ref()
 44→        .and_then(|h| h.shorthand().map(|s| s.to_string()));
 45→
 46→    let git_branches = repo
 47→        .branches(Some(git2::BranchType::Local))
 48→        .map_err(|e| format!("Failed to list branches: {}", e))?;
 49→
 50→    for branch_result in git_branches {
 51→        let (branch, _) = branch_result.map_err(|e| format!("Branch error: {}", e))?;
 52→        if let Some(name) = branch.name().ok().flatten() {
 53→            // Skip entire/ internal branches
 54→            if name.starts_with("entire/") {
 55→                continue;
 56→            }
 57→            branches.push(BranchInfo {
 58→                is_head: head_name.as_deref() == Some(name),
 59→                name: name.to_string(),
 60→                checkpoint_count: 0, // TODO: count from checkpoint branch
 61→            });
 62→        }
 63→    }
 64→
 65→    Ok(branches)
 66→}
 67→
 68→pub fn list_worktrees(repo: &Repository) -> Result<Vec<WorktreeInfo>, String> {
 69→    let mut worktrees = Vec::new();
 70→    let wt_names = repo
 71→        .worktrees()
 72→        .map_err(|e| format!("Failed to list worktrees: {}", e))?;
 73→
 74→    for name in wt_names.iter() {
 75→        if let Some(name) = name {
 76→            if let Ok(wt) = repo.find_worktree(name) {
 77→                let wt_path = wt.path().to_string_lossy().to_string();
 78→                // Try to detect branch from worktree
 79→                let branch = detect_worktree_branch(&wt_path).unwrap_or_else(|| name.to_string());
 80→                worktrees.push(WorktreeInfo {
 81→                    path: wt_path,
 82→                    branch,
 83→                    is_main: false,
 84→                });
 85→            }
 86→        }
 87→    }
 88→
 89→    Ok(worktrees)
 90→}
 91→
 92→fn detect_worktree_branch(wt_path: &str) -> Option<String> {
 93→    let head_path = Path::new(wt_path).join(".git");
 94→    // Worktree .git is a file pointing to the main repo's worktree dir
 95→    if head_path.is_file() {
 96→        if let Ok(repo) = Repository::open(wt_path) {
 97→            if let Ok(head) = repo.head() {
 98→                return head.shorthand().map(|s| s.to_string());
 99→            }
100→        }
101→    }
102→    None
103→}
104→
105→pub fn get_repo_info(path: &str) -> Result<RepoInfo, String> {
106→    let repo = open_repo(path)?;
107→    let name = Path::new(path)
108→        .file_name()
109→        .map(|n| n.to_string_lossy().to_string())
110→        .unwrap_or_else(|| "unknown".to_string());
111→
112→    let mut branches = list_branches(&repo)?;
113→    let worktrees = list_worktrees(&repo)?;
114→
115→    // Count checkpoints per branch from the checkpoint tree
116→    let counts = count_checkpoints_per_branch(&repo);
117→    for branch in &mut branches {
118→        if let Some(&count) = counts.get(&branch.name) {
119→            branch.checkpoint_count = count;
120→        }
121→    }
122→
123→    Ok(RepoInfo {
124→        path: path.to_string(),
125→        name,
126→        branches,
127→        worktrees,
128→        registered: false,
129→    })
130→}
