213→
214→pub fn delete_worktree(
215→    repo_path: &str,
216→    worktree_path: &str,
217→    branch_name: &str,
218→    force: bool,
219→) -> Result<(), String> {
220→    if branch_name.trim().is_empty() {
221→        return Err("Branch name is required".to_string());
222→    }
223→    if worktree_path.trim().is_empty() {
224→        return Err("Worktree path is required".to_string());
225→    }
226→    if paths_match(repo_path, worktree_path) {
227→        return Err("Cannot delete the main repository checkout".to_string());
228→    }
229→
230→    open_repo(repo_path)?;
231→
232→    let remove_args = build_git_worktree_remove_args(worktree_path.trim(), force);
233→    run_git_command(repo_path, &remove_args)?;
234→
235→    let delete_args = build_git_branch_delete_args(branch_name.trim(), force);
236→    run_git_command(repo_path, &delete_args)
237→}
238→
239→fn run_git_command(repo_path: &str, args: &[String]) -> Result<(), String> {
240→    let output = Command::new("git")
241→        .args(args)
242→        .current_dir(repo_path)
243→        .output()
244→        .map_err(|e| format!("Failed to run git: {}", e))?;
245→
246→    if output.status.success() {
247→        return Ok(());
248→    }
249→
250→    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
251→    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
252→    let message = if !stderr.is_empty() {
253→        stderr
254→    } else if !stdout.is_empty() {
255→        stdout
256→    } else {
257→        "Git command failed".to_string()
258→    };
259→
260→    Err(message)
261→}
262→
263→fn paths_match(left: &str, right: &str) -> bool {
264→    let left = std::fs::canonicalize(left).ok();
265→    let right = std::fs::canonicalize(right).ok();
266→    matches!((left, right), (Some(left), Some(right)) if left == right)
267→}
