 52→/// Get the journal directory, reading from app settings or falling back to ~/.entire/journal/.
 53→pub fn journal_dir() -> PathBuf {
 54→    let settings = crate::config::read_app_settings();
 55→    let dir = if let Some(ref p) = settings.journal_path {
 56→        PathBuf::from(p)
 57→    } else {
 58→        let home = std::env::var("HOME").unwrap_or_default();
 59→        PathBuf::from(home).join(".entire/journal")
 60→    };
 61→    let _ = fs::create_dir_all(&dir);
 62→    dir
 63→}
