 65→/// List journal entries from markdown files, sorted newest first.
 66→/// `limit` defaults to 100.
 67→pub fn list_entries(limit: usize) -> Result<Vec<JournalEntry>, String> {
 68→    let dir = journal_dir();
 69→    if !dir.exists() {
 70→        return Ok(Vec::new());
 71→    }
 72→
 73→    let mut files: Vec<_> = fs::read_dir(&dir)
 74→        .map_err(|e| format!("Failed to read journal dir: {}", e))?
 75→        .filter_map(|e| e.ok())
 76→        .filter(|e| {
 77→            e.path()
 78→                .extension()
 79→                .map_or(false, |ext| ext == "md")
 80→        })
 81→        .collect();
 82→
 83→    // Sort by filename descending (YYYY-MM-DD.md sorts chronologically)
 84→    files.sort_by(|a, b| b.file_name().cmp(&a.file_name()));
 85→    files.truncate(limit);
 86→
 87→    let mut entries = Vec::new();
 88→    for file in files {
 89→        let content = fs::read_to_string(file.path())
 90→            .map_err(|e| format!("Failed to read {}: {}", file.path().display(), e))?;
 91→        match parse_markdown(&content) {
 92→            Ok(entry) => entries.push(entry),
 93→            Err(e) => eprintln!("Skipping {}: {}", file.path().display(), e),
 94→        }
 95→    }
 96→
 97→    Ok(entries)
 98→}
