100→/// Get a single journal entry by date (YYYY-MM-DD).
101→pub fn get_entry(date: &str) -> Result<JournalEntry, String> {
102→    let path = journal_dir().join(format!("{}.md", date));
103→    if !path.exists() {
104→        return Err(format!("No journal entry for {}", date));
105→    }
106→    let content = fs::read_to_string(&path)
107→        .map_err(|e| format!("Failed to read entry: {}", e))?;
108→    parse_markdown(&content)
109→}
110→
111→/// Get date info for the date jumper rail.
112→pub fn list_dates(limit: usize) -> Result<Vec<JournalDateInfo>, String> {
113→    let dir = journal_dir();
114→
115→    // Build a set of dates that have entries
116→    let mut entry_dates = std::collections::HashSet::new();
117→    let mut stats_map = std::collections::HashMap::new();
118→
119→    if dir.exists() {
120→        if let Ok(read_dir) = fs::read_dir(&dir) {
121→            for entry in read_dir.filter_map(|e| e.ok()) {
122→                let path = entry.path();
123→                if path.extension().map_or(false, |ext| ext == "md") {
124→                    if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
125→                        entry_dates.insert(stem.to_string());
126→                        // Quick parse frontmatter for stats
127→                        if let Ok(content) = fs::read_to_string(&path) {
128→                            if let Ok(parsed) = parse_frontmatter_only(&content) {
129→                                stats_map.insert(stem.to_string(), parsed);
130→                            }
131→                        }
132→                    }
133→                }
134→            }
135→        }
136→    }
137→
138→    // Generate last `limit` days
139→    let today = current_date();
140→    let mut dates = Vec::new();
141→    for i in 0..limit {
142→        let date = subtract_days(&today, i as i64);
143→        let has_entry = entry_dates.contains(&date);
144→        let activity_level = stats_map
145→            .get(&date)
146→            .map(|s| {
147→                // Scale lines_changed to 0-4
148→                match s.lines_changed {
149→                    0 => 0,
150→                    1..=100 => 1,
151→                    101..=500 => 2,
152→                    501..=1000 => 3,
153→                    _ => 4,
154→                }
155→            })
156→            .unwrap_or(0);
157→
158→        dates.push(JournalDateInfo {
159→            date,
160→            has_entry,
161→            activity_level,
162→        });
163→    }
164→
165→    Ok(dates)
166→}
