177→/// Parse a journal markdown file into a JournalEntry.
178→pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
179→    // Split frontmatter from body
180→    let (frontmatter, body) = split_frontmatter(content)?;
181→
182→    // Parse YAML frontmatter
183→    let date = extract_yaml_field(&frontmatter, "date")
184→        .ok_or("Missing date in frontmatter")?;
185→    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
186→        .unwrap_or_default();
187→    let stats = parse_frontmatter_only(content)?;
188→
189→    // Parse body into repo sections and other work
190→    let (repos, other_work) = parse_body(&body);
191→
192→    Ok(JournalEntry {
193→        date,
194→        generated_at,
195→        repos,
196→        other_work,
197→        stats,
198→    })
199→}
200→
201→fn split_frontmatter(content: &str) -> Result<(String, String), String> {
202→    let content = content.trim();
203→    if !content.starts_with("---") {
204→        return Err("No frontmatter found".to_string());
205→    }
206→    let rest = &content[3..];
207→    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
208→    let frontmatter = rest[..end].trim().to_string();
209→    let body = rest[end + 3..].trim().to_string();
210→    Ok((frontmatter, body))
211→}
212→
213→fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
214→    for line in yaml.lines() {
215→        let line = line.trim();
216→        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
217→            let value = rest.trim().trim_matches('"').trim_matches('\'');
218→            if !value.is_empty() {
219→                return Some(value.to_string());
220→            }
221→        }
222→    }
223→    None
224→}
225→
226→fn parse_frontmatter_only(content: &str) -> Result<JournalStats, String> {
227→    let (frontmatter, _) = split_frontmatter(content)?;
228→
229→    let lines_changed = extract_yaml_field(&frontmatter, "lines_changed")
230→        .and_then(|v| v.parse().ok())
231→        .unwrap_or(0);
232→    let sessions = extract_yaml_field(&frontmatter, "sessions")
233→        .and_then(|v| v.parse().ok())
234→        .unwrap_or(0);
235→    let prs = extract_yaml_field(&frontmatter, "prs")
236→        .and_then(|v| v.parse().ok())
237→        .unwrap_or(0);
238→    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
239→        .and_then(|v| v.parse().ok())
240→        .unwrap_or(0);
241→    let tokens = extract_yaml_field(&frontmatter, "tokens")
242→        .and_then(|v| v.parse().ok())
243→        .unwrap_or(0);
244→
245→    Ok(JournalStats {
246→        lines_changed,
247→        sessions,
248→        prs,
249→        ai_authored_pct,
250→        tokens,
251→    })
252→}
253→
254→fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
255→    let mut repos = Vec::new();
256→    let mut other_work = Vec::new();
257→    let mut current_repo: Option<RepoSection> = None;
258→    let mut in_prs = false;
259→    let mut in_other_work = false;
260→
261→    for line in body.lines() {
262→        let trimmed = line.trim();
263→
264→        // H2 heading = repo name or "Other Work"
265→        if let Some(heading) = trimmed.strip_prefix("## ") {
266→            // Save previous repo
267→            if let Some(repo) = current_repo.take() {
268→                repos.push(repo);
269→            }
270→            in_prs = false;
271→
272→            if heading == "Other Work" {
273→                in_other_work = true;
274→                continue;
275→            }
276→
277→            in_other_work = false;
278→            current_repo = Some(RepoSection {
279→                name: heading.to_string(),
280→                lines_added: 0,
281→                lines_removed: 0,
282→                accomplishments: Vec::new(),
283→                pull_requests: Vec::new(),
284→            });
285→            continue;
286→        }
287→
288→        // H3 heading = "Pull Requests" subsection
289→        if trimmed.starts_with("### Pull Requests") {
290→            in_prs = true;
291→            continue;
292→        }
293→
294→        // Lines diff stats: _+716 -131_
295→        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
296→            if let Some(ref mut repo) = current_repo {
297→                let inner = &trimmed[1..trimmed.len() - 1];
298→                let parts: Vec<&str> = inner.split_whitespace().collect();
299→                if parts.len() == 2 {
300→                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
301→                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
302→                }
303→            }
304→            continue;
305→        }
306→
307→        // Bullet points
308→        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
309→            if in_other_work {
310→                other_work.push(bullet_content.to_string());
311→            } else if in_prs {
312→                if let Some(ref mut repo) = current_repo {
313→                    if let Some(pr) = parse_pr_line(bullet_content) {
314→                        repo.pull_requests.push(pr);
315→                    }
316→                }
317→            } else if let Some(ref mut repo) = current_repo {
318→                repo.accomplishments.push(bullet_content.to_string());
319→            }
320→        }
321→    }
322→
323→    // Don't forget last repo
324→    if let Some(repo) = current_repo {
325→        repos.push(repo);
326→    }
327→
328→    (repos, other_work)
329→}
