 39→// --- Registry persistence for manually registered repos ---
 40→
 41→#[derive(Debug, Serialize, Deserialize, Default)]
 42→struct RepoRegistry {
 43→    repos: Vec<String>,
 44→    #[serde(default)]
 45→    blocked: Vec<String>,
 46→}
 47→
 48→fn registry_path() -> PathBuf {
 49→    let home = dirs_next().unwrap_or_default();
 50→    PathBuf::from(home).join(".entire").join("registered-repos.json")
 51→}
 52→
 53→fn load_registry() -> RepoRegistry {
 54→    let path = registry_path();
 55→    let content = match fs::read_to_string(&path) {
 56→        Ok(c) => c,
 57→        Err(_) => return RepoRegistry::default(),
 58→    };
 59→    serde_json::from_str::<RepoRegistry>(&content).unwrap_or_default()
 60→}
 61→
 62→fn load_registered_repos() -> Vec<String> {
 63→    load_registry().repos
 64→}
 65→
 66→fn save_registry(registry: &RepoRegistry) -> Result<(), String> {
 67→    let path = registry_path();
 68→    if let Some(parent) = path.parent() {
 69→        fs::create_dir_all(parent).map_err(|e| format!("Failed to create ~/.entire: {}", e))?;
 70→    }
 71→    let content =
 72→        serde_json::to_string_pretty(registry).map_err(|e| format!("Failed to serialize: {}", e))?;
 73→    fs::write(&path, content).map_err(|e| format!("Failed to write registry: {}", e))
 74→}
 75→
 76→fn save_registered_repos(repos: &[String]) -> Result<(), String> {
 77→    let mut registry = load_registry();
 78→    registry.repos = repos.to_vec();
 79→    save_registry(&registry)
 80→}
 81→
 82→pub fn register_repo(path: &str) -> Result<(), String> {
 83→    let p = Path::new(path);
 84→
 85→    if !p.is_dir() {
 86→        return Err("Path is not a directory".to_string());
 87→    }
 88→
 89→    // Validate it's a git repo
 90→    git2::Repository::open(p).map_err(|_| "Not a git repository".to_string())?;
 91→
 92→    // Validate .entire is enabled
 93→    if !is_entire_enabled(path) {
 94→        return Err("Repository does not have Entire enabled (.entire/settings.json with enabled: true)".to_string());
 95→    }
 96→
 97→    // Canonicalize to avoid duplicates from different path representations
 98→    let canonical = p
 99→        .canonicalize()
100→        .map_err(|e| format!("Failed to resolve path: {}", e))?
101→        .to_string_lossy()
102→        .to_string();
103→
104→    let mut registry = load_registry();
105→    // Unblock if previously blocked
106→    registry.blocked.retain(|r| r != &canonical && r != path);
107→    if !registry.repos.contains(&canonical) {
108→        registry.repos.push(canonical);
109→    }
110→    save_registry(&registry)
111→}
112→
113→pub fn block_repo(path: &str) -> Result<(), String> {
114→    let canonical = Path::new(path)
115→        .canonicalize()
116→        .map(|p| p.to_string_lossy().to_string())
117→        .unwrap_or_else(|_| path.to_string());
118→
119→    let mut registry = load_registry();
120→    // Also unregister if it was registered
121→    registry.repos.retain(|r| r != &canonical && r != path);
122→    if !registry.blocked.contains(&canonical) {
123→        registry.blocked.push(canonical);
124→    }
125→    save_registry(&registry)
126→}
127→
128→pub fn unregister_repo(path: &str) -> Result<(), String> {
129→    let mut repos = load_registered_repos();
130→    let canonical = Path::new(path)
131→        .canonicalize()
132→        .map(|p| p.to_string_lossy().to_string())
133→        .unwrap_or_else(|_| path.to_string());
134→
135→    repos.retain(|r| r != &canonical && r != path);
136→    save_registered_repos(&repos)
137→}
138→
139→pub fn get_registered_repos() -> Vec<String> {
140→    load_registered_repos()
141→}
142→
143→/// Return registered repos that are not blocked and still valid
144→pub fn discover_repos() -> Vec<String> {
145→    let registry = load_registry();
146→    let blocked: HashSet<String> = registry.blocked.into_iter().collect();
147→    let mut seen = HashSet::new();
148→    let mut repos = Vec::new();
149→
150→    for registered in registry.repos {
151→        if !blocked.contains(&registered) && seen.insert(registered.clone()) {
152→            if Path::new(&registered).is_dir() && is_entire_enabled(&registered) {
153→                repos.push(registered);
154→            }
155→        }
156→    }
157→
158→    repos
159→}
