236→/// Find the most recent commit on a branch at or before the given timestamp.
237→/// Returns (sha, message) or None if not found.
238→fn resolve_commit_from_branch(
239→    repo: &Repository,
240→    branch_name: &str,
241→    created_at: &str,
242→) -> Option<(String, String)> {
243→    if branch_name.is_empty() || created_at.is_empty() {
244→        return None;
245→    }
246→
247→    let branch = repo.find_branch(branch_name, git2::BranchType::Local).ok()?;
248→    let branch_commit = branch.get().peel_to_commit().ok()?;
249→
250→    // Parse the checkpoint created_at as a unix timestamp for comparison
251→    let checkpoint_ts = parse_iso_timestamp(created_at)?;
252→
253→    // Walk commits from branch HEAD backward
254→    let mut revwalk = repo.revwalk().ok()?;
255→    revwalk.push(branch_commit.id()).ok()?;
256→    revwalk.set_sorting(git2::Sort::TIME).ok()?;
257→
258→    for oid in revwalk {
259→        let oid = oid.ok()?;
260→        let commit = repo.find_commit(oid).ok()?;
261→        let commit_ts = commit.time().seconds();
262→
263→        // Find the first commit whose time is at or before the checkpoint
264→        if commit_ts <= checkpoint_ts {
265→            let sha = oid.to_string();
266→            let message = commit
267→                .summary()
268→                .unwrap_or("")
269→                .to_string();
270→            return Some((sha, message));
271→        }
272→    }
273→
274→    None
275→}
276→
277→/// Parse an ISO 8601 timestamp string to unix seconds
278→fn parse_iso_timestamp(s: &str) -> Option<i64> {
279→    // Handle formats like "2026-03-16T21:10:30.808196Z" and "2026-03-16T21:10:30Z"
280→    let s = s.trim();
281→    // Strip fractional seconds and Z
282→    let s = s.trim_end_matches('Z');
283→    let s = if let Some(dot_pos) = s.rfind('.') {
284→        &s[..dot_pos]
285→    } else {
286→        s
287→    };
288→
289→    // Parse "YYYY-MM-DDTHH:MM:SS"
290→    let parts: Vec<&str> = s.split('T').collect();
291→    if parts.len() != 2 {
292→        return None;
293→    }
294→    let date_parts: Vec<i64> = parts[0].split('-').filter_map(|p| p.parse().ok()).collect();
295→    let time_parts: Vec<i64> = parts[1].split(':').filter_map(|p| p.parse().ok()).collect();
296→
297→    if date_parts.len() != 3 || time_parts.len() != 3 {
298→        return None;
299→    }
300→
301→    let (year, month, day) = (date_parts[0], date_parts[1], date_parts[2]);
302→    let (hour, min, sec) = (time_parts[0], time_parts[1], time_parts[2]);
303→
304→    // Simple days-since-epoch calculation (good enough for comparison)
305→    let mut days: i64 = 0;
306→    for y in 1970..year {
307→        days += if y % 4 == 0 && (y % 100 != 0 || y % 400 == 0) { 366 } else { 365 };
308→    }
309→    let month_days = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
310→    let is_leap = year % 4 == 0 && (year % 100 != 0 || year % 400 == 0);
